# Base shapes module - defines concrete base class
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    def describe(self) -> str:
        return f"Shape: {self._name}"

    def get_bounds(self) -> tuple[float, float]:
        return (0.0, 0.0)

    def get_area(self) -> float:
        return 0.0

