# Extended shapes - concrete implementations
from module_shapes import Shape

class Rectangle(Shape):
    _width: float
    _height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self._width = width
        self._height = height

    def get_width(self) -> float:
        return self._width

    def get_height(self) -> float:
        return self._height

    def get_area(self) -> float:
        return self._width * self._height

    def describe(self) -> str:
        return f"{self._name} ({self._width}x{self._height})"

    def draw(self) -> str:
        return f"Drawing rectangle {self._width}x{self._height}"

    def get_bounds(self) -> tuple[float, float]:
        return (self._width, self._height)

class Circle(Shape):
    _radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self._radius = radius

    def get_radius(self) -> float:
        return self._radius

    def get_area(self) -> float:
        PI = 3.14159
        return PI * self._radius * self._radius

    def describe(self) -> str:
        return f"{self._name} (r={self._radius})"

    def draw(self) -> str:
        return f"Drawing circle with radius {self._radius}"

    def get_bounds(self) -> tuple[float, float]:
        size = self._radius * 2.0
        return (size, size)
